const allItems = $input.all();
const alerts = Array.isArray(allItems[0]?.json) ? allItems[0].json : [];
const github = Array.isArray(allItems[1]?.json) ? allItems[1].json : [];
const metrics = Array.isArray(allItems[2]?.json) ? allItems[2].json : [];

const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 7);
const weekLabel = weekStart.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
const today = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

const sections = [];

// Infrastructure
const criticalAlerts = alerts.filter(a => (a.importance || 0) >= 8);
sections.push(`📊 INFRASTRUCTURE (${weekLabel} – ${today})`);
sections.push(`Health alerts: ${alerts.length} total, ${criticalAlerts.length} critical`);
if (criticalAlerts.length > 0) {
  sections.push('Critical: ' + criticalAlerts.slice(0, 3).map(a => a.content?.split('\n')[0]).join('; '));
}

// GitHub
sections.push('');
sections.push(`💻 CODE ACTIVITY`);
sections.push(`GitHub digests: ${github.length} entries`);
if (github.length > 0) {
  sections.push('Latest: ' + (github[0]?.content?.split('\n')[1] || 'no commits recorded'));
}

// Metrics
sections.push('');
sections.push(`📈 SYSTEM METRICS`);
if (metrics.length > 0) {
  const latest = metrics[0];
  sections.push('Latest snapshot: ' + (latest.content?.split('\n')[0] || 'unavailable'));
}

const digest = sections.join('\n');
const title = `Weekly Digest: ${weekLabel} – ${today}`;

return [{
  json: {
    title,
    digest,
    alert_count: alerts.length,
    critical_count: criticalAlerts.length,
    github_entries: github.length,
    timestamp: new Date().toISOString()
  }
}];
